class Solution:
    def largestPalindrome(self, n, k):
        h = (n + 1) // 2
        best = None
        lo = 10 ** (h - 1) if h > 1 else 1
        hi = 10 ** h - 1 if h > 1 else 9
        for half_num in range(hi, lo - 1, -1):
            half = str(half_num)
            if n % 2 == 1:
                full = half + half[-2::-1]
            else:
                full = half + half[::-1]
            if int(full) % k == 0:
                best = full
                break
        return best

