class Solution:
    def largestPalindrome(self, n, k):
        h = (n + 1) // 2
        mid_is_self = (n % 2 == 1)
        weight = [0] * h
        for j in range(h):
            if mid_is_self and j == h - 1:
                weight[j] = pow(10, j, k)
            else:
                weight[j] = (pow(10, n - 1 - j, k) + pow(10, j, k)) % k
        achievable = [None] * (h + 1)
        achievable[h] = {0}
        for i in range(h - 1, -1, -1):
            reach = set()
            lo = 1 if i == 0 else 0
            nxt = achievable[i + 1]
            for d in range(lo, 10):
                contrib = (d * weight[i]) % k
                for r in nxt:
                    reach.add((contrib + r) % k)
            achievable[i] = reach
        digits = [0] * h
        need = 0
        for i in range(h):
            lo = 1 if i == 0 else 0
            for d in range(9, lo - 1, -1):
                contrib = (d * weight[i]) % k
                rem_after = (need - contrib) % k
                if rem_after in achievable[i + 1]:
                    digits[i] = d
                    need = rem_after
                    break
        if mid_is_self:
            full = digits + digits[-2::-1]
        else:
            full = digits + digits[::-1]
        return ''.join(str(x) for x in full)

