var largestPalindrome = function(n, k) {
    function modpow(base, exp, mod) {
        if (mod === 1) return 0;
        let result = 1 % mod;
        base = base % mod;
        while (exp > 0) {
            if (exp & 1) result = (result * base) % mod;
            exp = Math.floor(exp / 2);
            base = (base * base) % mod;
        }
        return result;
    }
    const h = Math.floor((n + 1) / 2);
    const midIsSelf = (n % 2 === 1);
    const weight = new Array(h).fill(0);
    for (let j = 0; j < h; j++) {
        if (midIsSelf && j === h - 1) {
            weight[j] = modpow(10, j, k);
        } else {
            weight[j] = (modpow(10, n - 1 - j, k) + modpow(10, j, k)) % k;
        }
    }
    const achievable = new Array(h + 1);
    achievable[h] = new Set([0]);
    for (let i = h - 1; i >= 0; i--) {
        const reach = new Set();
        const lo = (i === 0) ? 1 : 0;
        const nxt = achievable[i + 1];
        for (let d = lo; d <= 9; d++) {
            const contrib = (d * weight[i]) % k;
            for (const r of nxt) {
                reach.add((contrib + r) % k);
            }
        }
        achievable[i] = reach;
    }
    const digits = new Array(h).fill(0);
    let need = 0;
    for (let i = 0; i < h; i++) {
        const lo = (i === 0) ? 1 : 0;
        for (let d = 9; d >= lo; d--) {
            const contrib = (d * weight[i]) % k;
            const remAfter = ((need - contrib) % k + k) % k;
            if (achievable[i + 1].has(remAfter)) {
                digits[i] = d;
                need = remAfter;
                break;
            }
        }
    }
    let fullDigits;
    if (midIsSelf) {
        fullDigits = digits.concat(digits.slice(0, h - 1).reverse());
    } else {
        fullDigits = digits.concat(digits.slice().reverse());
    }
    return fullDigits.join('');
};
